+
+    DispatchOutcome {
+        payload: json!({
+            "status": "ok",
+            "command": "pipeline",
+            "subcommand": "show",
+            "path": path.display().to_string(),
+            "definition": definition,
+            "validation": validation,
+            "next_actions": [
