+    path: &std::path::Path,
+    definition: Option<&pipe::PipelineDefinition>,
+    validation: &pipe::PipelineValidation,
+) -> DispatchOutcome {
+    let payload = definition.map_or_else(
+        || {
+            json!({
+                "status": "error",
