+                    "message": "The pipeline definition is structurally invalid.",
+                    "details": validation.errors,
+                    "next_actions": [
+                        format!("fwc pipeline show {}", path.display()),
+                        format!("fwc pipeline validate {}", path.display()),
+                    ],
+                },
+            })
+        },
